# 建立一個新的 Excel 活頁簿
wb = openpyxl.Workbook()
sheet = wb.active
sheet.title = "TOEIC High-Frequency Words"

# 1. 設定標題列
headers = ["單字 (Word)", "詞性 (POS)", "中文意思 (Meaning)", "例句 (Example Sentence)", "分類 (Category)"]
sheet.append(headers)

# 標題列格式化：粗體、背景顏色 (深藍色)、置中對齊
header_font = Font(bold=True, color="FFFFFF")
header_fill = PatternFill(start_color="4F81BD", end_color="4F81BD", fill_type="solid")
header_alignment = Alignment(horizontal="center", vertical="center")

for cell in sheet[1]:
    cell.font = header_font
    cell.fill = header_fill
    cell.alignment = header_alignment

# 2. 寫入單字資料
for word_data in words:
    sheet.append(word_data)

# 3. 設定資料內容的對齊方式與自動換行 (針對例句與長文字)
content_alignment = Alignment(vertical="center", wrap_text=True)
for row in sheet.iter_rows(min_row=2, max_row=len(words)+1, min_col=1, max_col=5):
    for cell in row:
        cell.alignment = content_alignment

# 4. 調整欄寬以符合閱讀需求
sheet.column_dimensions['A'].width = 20  # 單字
sheet.column_dimensions['B'].width = 12  # 詞性
sheet.column_dimensions['C'].width = 30  # 中文意思
sheet.column_dimensions['D'].width = 65  # 例句 (最寬)
sheet.column_dimensions['E'].width = 20  # 分類

# 5. 存檔
filename = "TOEIC_High_Frequency_Words.xlsx"
wb.save(filename)

print(f"匯出完成！成功將 {len(words)} 個單字儲存至 {filename}")
print(f"Total words: {len(words)}")